def build_otpauth_uri(
    account_name: str,
    issuer: str,
    secret: str,
    period: int = 30,
    digits: int = 6,
    algorithm: str = "SHA1",
) -> str:
    from urllib.parse import quote

    label = f"{quote(issuer)}:{quote(account_name)}"
    params = (
        f"secret={quote(secret)}"
        f"&issuer={quote(issuer)}"
        f"&algorithm={quote(algorithm)}"
        f"&digits={digits}"
        f"&period={period}"
    )
    return f"otpauth://totp/{label}?{params}"


